import{_ as a,p as e,q as r,a1 as h}from"./framework-39bdc1ba.js";const i={},d=h('<h2 id="泛型" tabindex="-1"><a class="header-anchor" href="#泛型" aria-hidden="true">#</a> 泛型</h2><h3 id="什么是泛型" tabindex="-1"><a class="header-anchor" href="#什么是泛型" aria-hidden="true">#</a> 什么是泛型？</h3><p>泛型：把类型明确的工作推迟到创建对象或调用方法的时候才去明确的特殊的类型</p><h3 id="泛型擦除是什么" tabindex="-1"><a class="header-anchor" href="#泛型擦除是什么" aria-hidden="true">#</a> 泛型擦除是什么</h3><p>因为泛型其实只是在编译器中实现的而虚拟机并不认识泛型类项，所以要在虚拟机中将泛型类型进行擦除。也就是说，在编译阶段使用泛型，运行阶段取消泛型，即擦除。 擦除是将泛型类型以其父类代替，如String 变成了Object 等。其实在使用的时候还是进行带强制类型的转化，只不过这是比较安全的转换，因为在编译阶段已经确保了数据的一致性。</p><hr><h2 id="序列化" tabindex="-1"><a class="header-anchor" href="#序列化" aria-hidden="true">#</a> 序列化</h2><h3 id="序列化是什么" tabindex="-1"><a class="header-anchor" href="#序列化是什么" aria-hidden="true">#</a> 序列化是什么？</h3><p>序列化是一种将对象转换成字节序列的过程，用于解决在对对象流进行读写操作时所引发的问题。序列化可以将对象的状态写在流里进行网络传输，或者保存到文件、数据库等系统里，并在需要的时候把该流读取出来重新构造成一个相同的对象</p><h3 id="简述-java-序列化与反序列化的实现" tabindex="-1"><a class="header-anchor" href="#简述-java-序列化与反序列化的实现" aria-hidden="true">#</a> 简述 Java 序列化与反序列化的实现</h3><ul><li>序列化：将 java 对象转化为字节序列，由此可以通过网络对象进行传输</li><li>反序列化：将字节序列转化为 java 对象</li><li>具体实现：实现 Serializable 接口，或实现 Externalizable 接口（Serializable接口的子接口）中的 writeExternal()与 readExternal()方法</li></ul><hr><h2 id="文档注释" tabindex="-1"><a class="header-anchor" href="#文档注释" aria-hidden="true">#</a> 文档注释</h2>',13),t=[d];function n(l,c){return e(),r("div",null,t)}const o=a(i,[["render",n],["__file","Java进阶.html.vue"]]);export{o as default};
